// Noncompliant: Macro parameters not properly parenthesized
#define SQUARE(x) x * x
#define MAX(a, b) a > b ? a : b

// Problems:
int result1 = SQUARE(2 + 3);  // Expands to: 2 + 3 * 2 + 3 = 11 (not 25)
int result2 = MAX(x++, y++);  // Side effects evaluated multiple times

compliant:
// Compliant: Macro parameters properly parenthesized
#define SQUARE(x) ((x) * (x))
#define MAX(a, b) (((a) > (b)) ? (a) : (b))

// Correct behavior:
int result1 = SQUARE(2 + 3);  // Expands to: ((2 + 3) * (2 + 3)) = 25
// Note: Still avoid side effects in macro arguments
